package com.agrios.platform.tasks.application;
import com.agrios.platform.cropcycle.domain.CropCycleRepository; import com.agrios.platform.common.exception.ResourceNotFoundException; import com.agrios.platform.tasks.api.*; import com.agrios.platform.tasks.domain.*; import java.time.Instant; import java.util.*; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional;
@Service public class RecurringTaskService {private final RecurringTaskScheduleRepository schedules;private final TaskRepository tasks;private final TaskEventRepository events;private final CropCycleRepository cycles;public RecurringTaskService(RecurringTaskScheduleRepository s,TaskRepository t,TaskEventRepository e,CropCycleRepository c){schedules=s;tasks=t;events=e;cycles=c;}
 @Transactional public RecurringTaskDtos.Response create(UUID tenant,UUID actor,RecurringTaskDtos.CreateRequest r){if(r.cropCycleId()!=null)cycles.findByIdAndTenantId(r.cropCycleId(),tenant).orElseThrow(()->new ResourceNotFoundException("CROP_CYCLE_NOT_FOUND","Crop cycle not found."));return RecurringTaskDtos.Response.from(schedules.save(RecurringTaskScheduleEntity.create(tenant,r.ownerContext(),r.ownerEntityId(),r.cropCycleId(),r.taskType(),r.title(),r.description(),r.priority(),r.assignedTo(),r.recurrenceType(),r.intervalValue(),r.startAt(),r.endAt(),actor)));}
 @Transactional public int generateDue(UUID tenant,UUID actor,Instant through){int generated=0;for(var s:schedules.findByTenantIdAndActiveTrueAndNextRunAtLessThanEqualOrderByNextRunAt(tenant,through)){while(s.active()&&!s.nextRunAt().isAfter(through)){var task=tasks.save(TaskEntity.create(tenant,s.ownerContext(),s.ownerEntityId(),s.cropCycleId(),s.taskType(),s.title(),s.description(),s.priority(),s.nextRunAt(),s.assignedTo(),actor));events.save(TaskEventEntity.create(task.id(),"GENERATED_FROM_RECURRING_SCHEDULE",actor,null,"{\"scheduleId\":\""+s.id()+"\"}"));s.advance(actor);generated++;}}return generated;}
}
